noncompliant:
// With default regex ^[A-Z][A-Z0-9_]*$:
exit: // Noncompliant - lowercase
  doCleanup();

camelCase: // Noncompliant - mixed case
  process();

my_label: // Noncompliant - lowercase with underscore
  cleanup();

compliant:
ERROR_HANDLER: // Compliant - uppercase with underscores
  handleError();

CLEAN_UP_LABEL: // Compliant
  performCleanup();
